import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';

export default function Sidebar({ projects=[], chats=[], activeProject, activeChat, onSelectProject, onSelectChat, onNewProject, onNewChat }) {
  const { user, logout } = useAuth();
  const { theme, toggle } = useTheme();
  const nav = useNavigate();
  const loc = useLocation();
  const [show, setShow] = useState(false);
  const [name, setName] = useState('');

  const create = () => { if (name.trim()) { onNewProject(name.trim()); setName(''); setShow(false); } };

  return (
    <div className="sb">
      <div className="sb-head"><div className="logo">W</div><div><h1>WHY Engine</h1><span>Coding Mind Analyzer</span></div></div>
      <div className="sb-nav">
        <button className={`nav-i ${loc.pathname==='/'?'on':''}`} onClick={()=>nav('/')}>⌨️ Workspace</button>
        <button className={`nav-i ${loc.pathname==='/dashboard'?'on':''}`} onClick={()=>nav('/dashboard')}>📊 Dashboard</button>
        <button className={`nav-i ${loc.pathname==='/profile'?'on':''}`} onClick={()=>nav('/profile')}>🧠 Thinking Profile</button>
      </div>
      <div className="sb-lbl">Projects<button className="btn-g btn-sm" onClick={()=>setShow(true)} style={{padding:'2px 8px',fontSize:'1rem'}}>+</button></div>
      {show && <div className="sb-inp"><input value={name} onChange={e=>setName(e.target.value)} placeholder="Project name..." onKeyDown={e=>e.key==='Enter'&&create()} autoFocus/><button className="btn btn-p btn-sm" onClick={create}>Add</button><button className="btn btn-g btn-sm" onClick={()=>{setShow(false);setName('')}}>✕</button></div>}
      <div className="sb-proj">
        {projects.map(p=>(
          <div key={p._id}>
            <div className={`p-item ${activeProject?._id===p._id?'on':''}`} onClick={()=>onSelectProject(p)}>📁 {p.name}</div>
            {activeProject?._id===p._id && <>
              {chats.map(c=><div key={c._id} className={`c-item ${activeChat?._id===c._id?'on':''}`} onClick={()=>onSelectChat(c)}>💬 {c.title}</div>)}
              <button className="new-c" onClick={onNewChat}>+ New Analysis</button>
            </>}
          </div>
        ))}
        {!projects.length && <div style={{padding:'24px 14px',color:'var(--text-3)',fontSize:'.82rem',textAlign:'center',lineHeight:1.6}}>No projects yet.<br/>Click + to create one.</div>}
      </div>
      <div className="sb-foot">
        <div style={{display:'flex',alignItems:'center',gap:8}}><div className="avatar">{user?.username?.[0]?.toUpperCase()||'?'}</div><span style={{fontSize:'.82rem',fontWeight:600}}>{user?.username}</span></div>
        <div style={{display:'flex',gap:4}}><button className="btn-i" onClick={toggle}>{theme==='dark'?'☀️':'🌙'}</button><button className="btn-i" onClick={logout}>⏏</button></div>
      </div>
    </div>
  );
}
